#include <bits/stdc++.h>
using namespace std;

long long sum=0,ans;
long long n,m,w,a[200005],t=0;

int main()
{
	scanf ("%lld%lld",&n,&m);
	for(int i=1;i<=n;i++)
	{
		scanf ("%lld",&a[i]);
	}
	if(n<=m)
	{
		printf("0");
		return 0;
	}
	sort(a+1,a+n+1);
	for(int i=n;i>=1;i--) 
	{ 
		t++;
		if(t==m) 
		{
			break;
		}
	}
	for(int i=1;i<=n-t;i++)
	{
		ans+=a[i];
	} 
	printf("%lld",ans);
	return 0;
}
